    public Object parseCurrency(Object rawCurrency)
    {
        Object currencyId = this.safeString(rawCurrency, "coin");
        Object code = this.safeCurrencyCode(currencyId);
        Object name = this.safeString(rawCurrency, "name");
        Object networks = new java.util.HashMap<String, Object>() {{}};
        Object chains = this.safeList(rawCurrency, "networkList", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(chains)); j++)
        {
            Object chain = this.safeDict(chains, j);
            Object networkId = this.safeString(chain, "network");
            Object networkCode = this.networkIdToCode(networkId, code);
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "info", chain );
    put( "id", networkId );
    put( "network", networkCode );
    put( "active", null );
    put( "deposit", WeexCore.this.safeBool(chain, "depositEnable") );
    put( "withdraw", WeexCore.this.safeBool(chain, "withdrawEnable") );
    put( "fee", WeexCore.this.safeNumber(chain, "withdrawFee") );
    put( "precision", WeexCore.this.safeNumber(chain, "withdrawIntegerMultiple") );
    put( "isDefault", WeexCore.this.safeBool(chain, "isDefault", false) );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", WeexCore.this.safeNumber(chain, "withdrawMin") );
            put( "max", null );
        }} );
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", WeexCore.this.safeNumber(chain, "depositDust") );
            put( "max", null );
        }} );
    }} );
}});
        }
        Object networkKeys = Helpers.objectKeys(networks);
        Object networksLength = Helpers.getArrayLength(networkKeys);
        Object emptyChains = Helpers.isEqual(networksLength, 0); // non-functional coins
        Object valueForEmpty = ((Helpers.isTrue(emptyChains))) ? false : null;
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "info", rawCurrency );
            put( "code", code );
            put( "id", currencyId );
            put( "type", "crypto" );
            put( "name", name );
            put( "active", null );
            put( "deposit", valueForEmpty );
            put( "withdraw", valueForEmpty );
            put( "fee", null );
            put( "precision", null );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", networks );
        }});
    }

    /**
     * @method
     * @name weex#fetchMarkets
     * @description retrieves data on all markets for exchagne
     * @see https://www.weex.com/api-doc/spot/ConfigAPI/GetProductInfo // spot
     * @see https://www.weex.com/api-doc/contract/Market_API/GetContractInfo // contract
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.GetValue(this.options, "adjustForTimeDifference")))
            {
                (this.loadTimeDifference()).join();
            }
            Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.publicGetApiV3ExchangeInfo(parameters), this.contractGetCapiV3MarketExchangeInfo(parameters)));
            var spotResponsecontractResponseVariable = (Helpers.promiseAll(promises)).join();
            var spotResponse = ((java.util.List<Object>) spotResponsecontractResponseVariable).get(0);
            var contractResponse = ((java.util.List<Object>) spotResponsecontractResponseVariable).get(1);
            Object spotArray = this.safeList(spotResponse, "symbols", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object contractArray = this.safeList(contractResponse, "symbols", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = this.arrayConcat(spotArray, contractArray);
            return this.parseMarkets(result);
        });

    }

