    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // spot
        //     {
        //         "symbol": "ETHUSDT",
        //         "priceChange": "-72.98",
        //         "priceChangePercent": "-0.033811",
        //         "lastPrice": "2085.46",
        //         "bidPrice": "2085.44",
        //         "bidQty": "1.53848",
        //         "askPrice": "2085.47",
        //         "askQty": "1.87504",
        //         "openPrice": "2158.44",
        //         "highPrice": "2168.40",
        //         "lowPrice": "2061.12",
        //         "volume": "157359.56105",
        //         "quoteVolume": "331284305.7193626",
        //         "openTime": 1775493000000,
        //         "closeTime": 1775579400000,
        //         "count": 59727
        //     }
        //
        // swap
        //     {
        //         "symbol": "ETHUSDT",
        //         "priceChange": "-75.49",
        //         "priceChangePercent": "-0.034992",
        //         "lastPrice": "2081.80",
        //         "openPrice": "2157.29",
        //         "highPrice": "2167.51",
        //         "lowPrice": "2059.17",
        //         "volume": "623160.426",
        //         "quoteVolume": "1310647345.19346",
        //         "openTime": 1775493000000,
        //         "closeTime": 1775579400000,
        //         "markPrice": "2081.8",
        //         "indexPrice": "2082.75"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        Object markPrice = this.safeString(ticker, "markPrice");
        Object marketType = "spot";
        if (Helpers.isTrue(!Helpers.isEqual(markPrice, null)))
        {
            marketType = "swap";
        }
        market = this.safeMarket(marketId, market, null, marketType);
        Object timestamp = this.safeInteger2(ticker, "closeTime", "time");
        final Object finalMarket = market;
        final Object finalMarkPrice = markPrice;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "timestamp", timestamp );
            put( "datetime", WeexCore.this.iso8601(timestamp) );
            put( "high", WeexCore.this.safeString(ticker, "highPrice") );
            put( "low", WeexCore.this.safeString(ticker, "lowPrice") );
            put( "bid", WeexCore.this.safeString(ticker, "bidPrice") );
            put( "bidVolume", WeexCore.this.safeString(ticker, "bidQty") );
            put( "ask", WeexCore.this.safeString(ticker, "askPrice") );
            put( "askVolume", WeexCore.this.safeString(ticker, "askQty") );
            put( "vwap", null );
            put( "open", WeexCore.this.safeString(ticker, "openPrice") );
            put( "close", WeexCore.this.safeString(ticker, "lastPrice") );
            put( "last", WeexCore.this.safeString(ticker, "lastPrice") );
            put( "previousClose", null );
            put( "change", WeexCore.this.safeString(ticker, "priceChange") );
            put( "percentage", WeexCore.this.safeString(ticker, "priceChangePercent") );
            put( "average", null );
            put( "baseVolume", WeexCore.this.safeString(ticker, "volume") );
            put( "quoteVolume", WeexCore.this.safeString(ticker, "quoteVolume") );
            put( "markPrice", finalMarkPrice );
            put( "indexPrice", WeexCore.this.safeString(ticker, "indexPrice") );
            put( "info", ticker );
        }}, market);
    }

