    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //     {
        //         "id": "875fba11-f8a1-42ad-915d-012ccb375e8a",
        //         "price": "2114.77",
        //         "qty": "0.01000",
        //         "quoteQty": "21.1477000",
        //         "time": 1775594995485,
        //         "isBuyerMaker": false,
        //         "isBestMatch": true
        //     }
        //
        // fetchMyTrades (spot)
        //     {
        //         "symbol": "DOGEUSDT",
        //         "id": 736825748291060702,
        //         "orderId": 736825748215563230,
        //         "price": "0.09349",
        //         "qty": "250.0",
        //         "quoteQty": "23.3725",
        //         "commission": "0.0233725",
        //         "time": 1775672947953,
        //         "isBuyer": false
        //     }
        //
        // fetchMyTrades (contract)
        //     {
        //         "id": 737074389731770728,
        //         "orderId": 737074043320009064,
        //         "symbol": "DOGEUSDT",
        //         "buyer": true,
        //         "commission": "0.00183500",
        //         "commissionAsset": "USDT",
        //         "maker": true,
        //         "price": "0.09175",
        //         "qty": "100",
        //         "quoteQty": "9.17500",
        //         "realizedPnl": "0",
        //         "side": "BUY",
        //         "positionSide": "LONG",
        //         "time": 1775732228692
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "time");
        Object isBuyer = this.safeBool(trade, "isBuyer");
        Object side = this.safeStringLower(trade, "side");
        Object isBuyerMaker = this.safeBool(trade, "isBuyerMaker");
        if (Helpers.isTrue(!Helpers.isEqual(isBuyer, null)))
        {
            side = ((Helpers.isTrue(isBuyer))) ? "buy" : "sell";
        } else if (Helpers.isTrue(!Helpers.isEqual(isBuyerMaker, null)))
        {
            side = ((Helpers.isTrue(isBuyerMaker))) ? "sell" : "buy";
        }
        Object isSpot = true;
        if (Helpers.isTrue(Helpers.isEqual(market, null)))
        {
            Object marketId = this.safeString(trade, "symbol");
            Object realizedPnl = this.safeString(trade, "realizedPnl");
            Object marketType = ((Helpers.isTrue((!Helpers.isEqual(realizedPnl, null))))) ? "swap" : "spot";
            market = this.safeMarket(marketId, null, null, marketType);
            isSpot = Helpers.isEqual(marketType, "spot");
        } else
        {
            isSpot = Helpers.GetValue(market, "spot");
        }
        Object fee = null;
        Object commission = this.safeString(trade, "commission");
        if (Helpers.isTrue(!Helpers.isEqual(commission, null)))
        {
            Object commissionAsset = this.safeString(trade, "commissionAsset");
            Object feeCurrency = this.safeCurrencyCode(commissionAsset);
            if (Helpers.isTrue(isSpot))
            {
                if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
                {
                    feeCurrency = Helpers.GetValue(market, "base");
                } else
                {
                    feeCurrency = Helpers.GetValue(market, "quote");
                }
            }
            final Object finalCommission = commission;
            final Object finalFeeCurrency = feeCurrency;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalCommission );
                put( "currency", finalFeeCurrency );
            }};
        }
        Object isMaker = this.safeBool(trade, "maker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(isMaker, null)))
        {
            takerOrMaker = ((Helpers.isTrue(isMaker))) ? "maker" : "taker";
        } else if (Helpers.isTrue(!Helpers.isEqual(isBuyerMaker, null)))
        {
            takerOrMaker = "taker";
        }
        final Object finalMarket = market;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", WeexCore.this.safeString(trade, "id") );
            put( "order", WeexCore.this.safeString(trade, "orderId") );
            put( "timestamp", timestamp );
            put( "datetime", WeexCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", null );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "side", finalSide );
            put( "price", WeexCore.this.safeString(trade, "price") );
            put( "amount", WeexCore.this.safeString(trade, "qty") );
            put( "cost", WeexCore.this.safeString(trade, "quoteQty") );
            put( "fee", finalFee );
        }}, market);
    }

