    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "id": 737191855967437160,
        //         "asset": "USDT",
        //         "symbol": "DOGEUSDT",
        //         "side": "LONG",
        //         "marginType": "CROSSED",
        //         "separatedMode": "COMBINED",
        //         "separatedOpenOrderId": 0,
        //         "leverage": "20.00",
        //         "size": "300",
        //         "openValue": "27.96900",
        //         "openFee": "0.02237520",
        //         "fundingFee": "0",
        //         "marginSize": "100",
        //         "isolatedMargin": "0",
        //         "isAutoAppendIsolatedMargin": false,
        //         "cumOpenSize": "300",
        //         "cumOpenValue": "27.96900",
        //         "cumOpenFee": "0.02237520",
        //         "cumCloseSize": "0",
        //         "cumCloseValue": "0",
        //         "cumCloseFee": "0",
        //         "cumFundingFee": "0",
        //         "cumLiquidateFee": "0",
        //         "createdMatchSequenceId": 5762536243,
        //         "updatedMatchSequenceId": 5762741613,
        //         "createdTime": 1775760234825,
        //         "updatedTime": 1775763170789,
        //         "unrealizePnl": "0.00600",
        //         "liquidatePrice": "0"
        //     }
        //
        // watchPoisions
        //     {
        //         "id": "739004481374519656",
        //         "coin": "USDT",
        //         "symbol": "DOGEUSDT",
        //         "side": "LONG",
        //         "marginMode": "CROSSED",
        //         "separatedMode": "COMBINED",
        //         "separatedOpenOrderId": "0",
        //         "leverage": "11",
        //         "size": "100",
        //         "openValue": "9.31100",
        //         "openFee": "0.00744880",
        //         "fundingFee": "0",
        //         "isolatedMargin": "0",
        //         "autoAppendIsolatedMargin": false,
        //         "cumOpenSize": "100",
        //         "cumOpenValue": "9.31100",
        //         "cumOpenFee": "0.00744880",
        //         "cumCloseSize": "0",
        //         "cumCloseValue": "0",
        //         "cumCloseFee": "0",
        //         "cumFundingFee": "0",
        //         "cumLiquidateFee": "0",
        //         "createdMatchSequenceId": "5792711540",
        //         "updatedMatchSequenceId": "5792711540",
        //         "createdTime": "1776192398399",
        //         "updatedTime": "1776192398399"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object errorMessage = this.safeString(position, "errorMsg");
        Object errorCode = this.safeString(position, "errorCode");
        if (Helpers.isTrue(!Helpers.isEqual(errorMessage, null)))
        {
            this.handleOrderOrPositionError(errorCode, errorMessage, position);
        }
        Object marketId = this.safeString2(position, "symbol", "coinId"); // coinId might be used in testnet: https://github.com/ccxt/ccxt/issues/28576#issuecomment-4439400273
        market = this.safeMarket(marketId, market, null, "contract");
        Object timestamp = this.safeInteger(position, "createdTime");
        Object marginType = this.safeString2(position, "marginType", "marginMode");
        Object marginMode = "cross";
        if (Helpers.isTrue(Helpers.isEqual(marginType, "ISOLATED")))
        {
            marginMode = "isolated";
        }
        Object separatedMode = this.safeString(position, "separatedMode");
        Object hedged = null;
        if (Helpers.isTrue(Helpers.isEqual(separatedMode, "COMBINED")))
        {
            hedged = false;
        } else if (Helpers.isTrue(Helpers.isEqual(separatedMode, "SEPARATED")))
        {
            hedged = true;
        }
        Object notional = this.safeString(position, "openValue");
        Object size = this.safeString(position, "size");
        Object entryPrice = Precise.stringDiv(notional, size);
        final Object finalMarket = market;
        final Object finalMarginMode = marginMode;
        final Object finalHedged = hedged;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "id", WeexCore.this.safeString2(position, "id", "positionId") );
            put( "timestamp", timestamp );
            put( "datetime", WeexCore.this.iso8601(timestamp) );
            put( "contracts", WeexCore.this.parseNumber(size) );
            put( "contractSize", null );
            put( "side", WeexCore.this.safeStringLower(position, "side") );
            put( "notional", WeexCore.this.parseNumber(notional) );
            put( "leverage", WeexCore.this.safeNumber(position, "leverage") );
            put( "unrealizedPnl", WeexCore.this.safeNumber(position, "unrealizePnl") );
            put( "realizedPnl", null );
            put( "collateral", null );
            put( "entryPrice", WeexCore.this.parseNumber(entryPrice) );
            put( "markPrice", null );
            put( "liquidationPrice", WeexCore.this.safeNumber(position, "liquidatePrice") );
            put( "marginMode", finalMarginMode );
            put( "hedged", finalHedged );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "initialMargin", WeexCore.this.safeNumber(position, "marginSize") );
            put( "initialMarginPercentage", null );
            put( "marginRatio", null );
            put( "lastUpdateTimestamp", WeexCore.this.safeInteger(position, "updatedTime") );
            put( "lastPrice", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
            put( "percentage", null );
            put( "info", position );
        }});
    }

