    public Object parseLeverage(Object leverage, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(leverage, "symbol");
        Object marginType = this.safeString(leverage, "marginType");
        Object marginMode = this.parseMarginType(marginType);
        Object crossLeverage = this.safeNumber(leverage, "crossLeverage");
        Object longLeverage = this.safeNumber(leverage, "isolatedLongLeverage");
        Object shortLeverage = this.safeNumber(leverage, "isolatedShortLeverage");
        if (Helpers.isTrue(Helpers.isEqual(marginMode, "cross")))
        {
            longLeverage = crossLeverage;
            shortLeverage = crossLeverage;
        }
        final Object finalMarginMode = marginMode;
        final Object finalLongLeverage = longLeverage;
        final Object finalShortLeverage = shortLeverage;
        return new java.util.HashMap<String, Object>() {{
            put( "info", leverage );
            put( "symbol", WeexCore.this.safeSymbol(marketId, market, null, "swap") );
            put( "marginMode", finalMarginMode );
            put( "longLeverage", finalLongLeverage );
            put( "shortLeverage", finalShortLeverage );
        }};
    }

    /**
     * @method
     * @name weex#setLeverage
     * @description set the level of leverage for a market
     * @see https://www.weex.com/api-doc/contract/Account_API/UpdateLeverageTRADE
     * @param {float} leverage the rate of leverage
     * @param {string} symbol unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.marginMode] 'cross' or 'isolated' (default is 'cross' if specific leverage parameters are not provided)
     * @param {number} [params.crossLeverage] *cross margin mode only* leverage for cross margin mode when marginMode is 'cross'
     * @param {number} [params.isolatedLongLeverage] *isolated margin mode only* leverage for long positions when marginMode is 'isolated'
     * @param {number} [params.isolatedShortLeverage] *isolated margin mode only* leverage for short positions when marginMode is 'isolated'
     * If specific leverage parameters are not provided
     * the leverage value will be applied to both long and short positions if marginMode is 'isolated'
     * or to cross margin mode if marginMode is 'cross'
     * If marginMode is not provided and specific leverage parameters are not provided too
     * the leverage value will be applied to cross leverage
     * @returns {object} response from the exchange
     */
    public java.util.concurrent.CompletableFuture<Object> setLeverage(Object leverage, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " setLeverage() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("setLeverage", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
            {
                Helpers.addElementToObject(request, "marginType", this.encodeMarginMode(marginMode));
            }
            Object isolatedLongLeverage = this.safeNumber(parameters, "isolatedLongLeverage");
            Object isolatedShortLeverage = this.safeNumber(parameters, "isolatedShortLeverage");
            Object crossLeverage = this.safeNumber(parameters, "crossLeverage");
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(isolatedLongLeverage, null))) && Helpers.isTrue((Helpers.isEqual(isolatedShortLeverage, null)))) && Helpers.isTrue((Helpers.isEqual(crossLeverage, null)))))
            {
                if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
                {
                    Helpers.addElementToObject(request, "isolatedLongLeverage", leverage);
                    Helpers.addElementToObject(request, "isolatedShortLeverage", leverage);
                } else
                {
                    Helpers.addElementToObject(request, "crossLeverage", leverage);
                }
            }
            return (this.contractPrivatePostCapiV3AccountLeverage(this.extend(request, parameters))).join();
        });

    }

    /**
     * @method
     * @name weex#fetchPositionMode
     * @description fetchs the position mode, hedged or one way
     * @see https://www.weex.com/api-doc/contract/Account_API/GetSymbolConfig
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an object detailing whether the market is in hedged or one-way mode
     */
    public java.util.concurrent.CompletableFuture<Object> fetchPositionMode(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.contractPrivateGetCapiV3AccountSymbolConfig(this.extend(request, parameters))).join();
            Object entry = this.safeDict(response, 0, new java.util.HashMap<String, Object>() {{}});
            Object separatedType = this.safeString(entry, "separatedType");
            final Object finalSeparatedType = separatedType;
            return new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "hedged", (Helpers.isEqual(finalSeparatedType, "SEPARATED")) );
            }};
        });

    }

    /**
     * @method
     * @name weex#setPositionMode
     * @description set hedged to true or false for a market
     * @see https://www.weex.com/api-doc/contract/Account_API/ChangeMarginModeTRADE
     * @param {bool} hedged set to true to use dualSidePosition
     * @param {string} symbol unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} params.marginMode 'cross' or 'isolated' (default is 'cross')
     * @returns {object} response from the exchange
     */
    public java.util.concurrent.CompletableFuture<Object> setPositionMode(Object hedged, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " setPositionMode() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("setPositionMode", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marginMode, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " setPositionMode() also sets marginMode, so a marginMode parameter is required")) ;
            }
            Object separatedType = ((Helpers.isTrue(hedged))) ? "SEPARATED" : "COMBINED";
            final Object finalMarginMode = marginMode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "marginType", WeexCore.this.encodeMarginMode(finalMarginMode) );
                put( "separatedType", separatedType );
            }};
            return (this.contractPrivatePostCapiV3AccountMarginType(this.extend(request, parameters))).join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> modifyMarginHelper(Object symbol, Object amount, Object type2, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object isolatedPositionId = this.safeStringN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("positionId", "id", "isolatedPositionId")));
            if (Helpers.isTrue(Helpers.isEqual(isolatedPositionId, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " modifyMarginHelper() requires a positionId parameter")) ;
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("positionId", "id")));
            Object market = this.market(symbol);
            final Object finalIsolatedPositionId = isolatedPositionId;
            final Object finalType = type;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "isolatedPositionId", finalIsolatedPositionId );
                put( "amount", WeexCore.this.costToPrecision(symbol, amount) );
                put( "type", finalType );
            }};
            Object parsedType = ((Helpers.isTrue((Helpers.isEqual(type, 1))))) ? "add" : "reduce";
            Object response = (this.contractPrivatePostCapiV3AccountPositionMargin(this.extend(request, parameters))).join();
            return this.extend(this.parseMarginModification(response, market), new java.util.HashMap<String, Object>() {{
                put( "amount", WeexCore.this.parseNumber(amount) );
                put( "type", parsedType );
            }});
        });

    }

    public Object parseMarginModification(Object data, Object... optionalArgs)
    {
        //
        //     {
        //         "code": "200",
        //         "msg": "success",
        //         "requestTime": 1764505776347
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object msg = this.safeString(data, "msg");
        Object status = ((Helpers.isTrue((Helpers.isEqual(msg, "success"))))) ? "ok" : "failed";
        Object timestamp = this.safeInteger(data, "requestTime");
        return new java.util.HashMap<String, Object>() {{
            put( "info", data );
            put( "symbol", WeexCore.this.safeString(market, "symbol") );
            put( "type", null );
            put( "marginMode", "isolated" );
            put( "amount", null );
            put( "total", null );
            put( "code", WeexCore.this.safeString(market, "settle") );
            put( "status", status );
            put( "timestamp", timestamp );
            put( "datetime", WeexCore.this.iso8601(timestamp) );
        }};
    }

